import React from "react";
import { ExplorerHeader } from "components/ExplorerHeader";
import { ExplorerFooter } from "components/ExplorerFooter";
import { DataSource, DataSourceContext } from "schema/DataSource";

interface ExplorerRenderProps {
  id: number;
  dataSource: DataSource;
}

export const AssetRender: React.FC<ExplorerRenderProps> = ({ id, dataSource }) => (
  <DataSourceContext.Provider value={dataSource}>
    <ExplorerHeader id={id} />
    <ExplorerFooter id={id} />
  </DataSourceContext.Provider>
);

